previewCss:
.darma-loader-darma-custom-422 {color: var(--loader-color, #db2777);
  --loader-secondary-color: var(--loader-secondary-color, #f9a8d4);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 60px;
  height: 30px;
  display: flex;
  --c:#0000 calc(100% - 5px),currentColor calc(100% - 4px) 96%,#0000;
  background:radial-gradient(farthest-side at bottom,var(--c)) 0 0,radial-gradient(farthest-side at top ,var(--c)) 100% 100%;
  background-size: calc(50% + 2px) 50%;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-422-l13 2s infinite linear;
}.darma-loader-darma-custom-422:before {content: "";
  flex: 1;
  background: inherit;
  transform: rotate(90deg);
}@keyframes darma-loader-darma-custom-422-l13 {100% {transform: rotate(1turn)}}

